import constFlaskURL from '../hooks/constFlaskURL'
// Create.
export const addRow = async (endpoint, data, header) => {
    await constFlaskURL.post(endpoint, data, { headers: {header} });
}
// Read.
export const readRows = async (enpoint) => {
    try {
        await constFlaskURL.get(enpoint);
    } catch (error) {
        console.error(error);
    }
}

export const getRow = async (endpoint, id_row) => {
    try {
        await constFlaskURL.get(`${endpoint}?id=${id_row}`);
    } catch (error) {
        console.error(error);
    } 
}
// Update.
export const updateRow = async (endpoint, id_row, data, { headers }) => {
    try {
        await constFlaskURL.put(`${endpoint}?id=${id_row}`, data, headers);
    } catch (error) {
        console.error(error);
    }
}
// Delete.
export const deleteRow = async (endpoint, id_row) => {
    try {
        await constFlaskURL.delete(`${endpoint}?id=${id_row}`);
    } catch (error) {
        console.error(error);
    } 
}
